

import React, { useState, useEffect } from 'react';
import "./CheckBoxSlide.css";


const CheckBoxSlide = ({disabled, initvalue, updChange, color}) => {
  const [active, setActive] = useState(false);
  const [initialize, setInitialize] = useState(false);


  useEffect(() => {
    if(!initialize){
      // setTimeout(()=>{  },1);
      setActive(initvalue)  
      setInitialize(true);
    }
    if(initvalue!==active){
      setActive(initvalue)  
    }
  });

  const handleChange = () => {
    if(!disabled){
      if(typeof updChange === 'function') {      
        updChange(!active)
      }  
      setActive(!active);  
    }
  }



  return (
    <>
      <div 
        className={`toggle-container ptoggle-button_hrm ${active?'_active':''}`} 
        style={color?{
            "--checkBox--button--color": color,
            "--checkBox--button--Active--color": color
        }:{}}
        onClick={()=>handleChange()} 
      >
        <div  className={`toggle-bar ptoggle-button_hrm`}></div>
        <div className={`toggle-button ptoggle-button_hrm`} >
          <div  className="pripple" style={{opacity: 0.00448}}></div>
          <div className="pripple"></div>
        </div>
        <div className={`toggle-label ptoggle-button_hrm`}></div>      
      </div>
    </>

  )
}

export default CheckBoxSlide
